temperatura = 15

if temperatura > 25:
    print("Hace calor")
else:
    print("Hace frío")

nota = 75

if nota >= 90:
    print("Excelente")
elif nota >= 70:
    print("Bien")
elif nota >= 60:
    print("Suficiente")
else:
    print("Reprobado")

edad = 25
carnet = True

if edad >= 18 and carnet:
    print("Puede conducir")

if edad < 16 or not carnet:
    print("No puede conducir")

# Del 1 al 5
for i in range(1, 6):
    print(i)

# Pares del 0 al 8
for i in range(0, 10, 2):
    print(i)

# break — sale del bucle
for i in range(10):
    if i == 5:
        break
    print(i)  # 0,1,2,3,4

# continue — salta la iteración
for i in range(5):
    if i == 2:
        continue
    print(i)  # 0,1,3,4
